// // This module implements a 4-bit binary counter with an enable signal.
// On each falling edge of CLK, if RST is 1, output Q is reset to 0. If EN is 1, the counter decrements by 1.
module counter_4bit (CLK, RST, EN, Q);
input CLK, RST, EN;
output reg [3:0] Q;

always @(posedge CLK or posedge RST) begin
    if (RST)
        Q <= 0;
    else if (EN)
        Q <= Q + 1;
end

endmodule
